\nimport \'package:flutter/material.dart\';\nimport \'../models/product.dart\';\nimport \'../services/admin_auth_service.dart\';\nimport \'../services/product_firestore_service.dart\';\nimport \'product_form_screen.dart\';\n\nclass AdminPanelScreen extends StatefulWidget {\n  const AdminPanelScreen({super.key});\n\n  @override\n  _AdminPanelScreenState createState() => _AdminPanelScreenState();\n}\n\nclass _AdminPanelScreenState extends State<AdminPanelScreen> {\n  final _productService = ProductFirestoreService();\n  final _authService = AdminAuthService();\n\n  void _navigateAndAddProduct() async {\n    await Navigator.of(context).push(\n      MaterialPageRoute(builder: (context) => const ProductFormScreen()),\n    );\n  }\n\n  void _navigateAndEditProduct(Product product) async {\n    await Navigator.of(context).push(\n      MaterialPageRoute(\n        builder: (context) => ProductFormScreen(product: product),\n      ),\n    );\n  }\n\n  @override\n  Widget build(BuildContext context) {\n    return Scaffold(\n      appBar: AppBar(\n        title: const Text(\'Admin Panel\'),\n        actions: [\n          IconButton(\n            icon: const Icon(Icons.logout),\n            onPressed: () => _authService.signOut(),\n            tooltip: \'Sign Out\',\n          ),\n        ],\n      ),\n      body: StreamBuilder<List<Product>>(\n        stream: _productService.getProducts(),\n        builder: (context, snapshot) {\n          if (snapshot.connectionState == ConnectionState.waiting) {\n            return const Center(child: CircularProgressIndicator());\n          }\n          if (!snapshot.hasData || snapshot.data!.isEmpty) {\n            return const Center(child: Text(\'No products found.\'));\n          }\n\n          final products = snapshot.data!;\n\n          return SingleChildScrollView(\n            scrollDirection: Axis.horizontal,\n            child: DataTable(\n              columns: const [\n                DataColumn(label: Text(\'Image\')),\n                DataColumn(label: Text(\'Name\')),\n                DataColumn(label: Text(\'Price\')),\n                DataColumn(label: Text(\'Actions\')),\n              ],\n              rows: products.map((product) {\n                return DataRow(\n                  cells: [\n                    DataCell(SizedBox(\n                      width: 50,\n                      height: 50,\n                      child: Image.network(product.imageUrl, fit: BoxFit.cover),\n                    )),\n                    DataCell(Text(product.name)),\n                    DataCell(Text(\'\$${product.price.toStringAsFixed(2)}\')),\n                    DataCell(Row(\n                      children: [\n                        IconButton(\n                          icon: const Icon(Icons.edit, color: Colors.blue),\n                          onPressed: () => _navigateAndEditProduct(product),\n                        ),\n                        IconButton(\n                          icon: const Icon(Icons.delete, color: Colors.red),\n                          onPressed: () => _productService.deleteProduct(product.id),\n                        ),\n                      ],\n                    )),\n                  ],\n                );\n              }).toList(),\n            ),\n          );\n        },\n      ),\n      floatingActionButton: FloatingActionButton(\n        onPressed: _navigateAndAddProduct,\n        child: const Icon(Icons.add),\n        tooltip: \'Add Product\',\n      ),\n    );\n  }\n}\n